#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct { float x, y, z; } V;
V v(float x, float y, float z) { V r={x,y,z}; return r; }
V vadd(V a, V b) { return v(a.x+b.x, a.y+b.y, a.z+b.z); }
V vsub(V a, V b) { return v(a.x-b.x, a.y-b.y, a.z-b.z); }
V vmul(V a, float t) { return v(a.x*t, a.y*t, a.z*t); }
float vdot(V a, V b) { return a.x*b.x + a.y*b.y + a.z*b.z; }
float vlen(V v) { return sqrtf(vdot(v,v)); }
V vnorm(V a) { float l=vlen(a); return v(a.x/l, a.y/l, a.z/z); }

// Scene parameters
V cam = {0, 0, -5};
V sph_center = {0, 0, 0};
float sph_r = 1.0;
float plane_y = -1.5;
V light = {-1, 2, -1};

float intersect_sphere(V ro, V rd, V sc, float sr) {
    V oc = vsub(ro, sc);
    float b = vdot(oc, rd);
    float c = vdot(oc, oc) - sr*sr;
    float h = b*b - c;
    if (h < 0) return -1;
    return -b - sqrtf(h);
}

float intersect_plane(V ro, V rd, float py) {
    if (fabsf(rd.y) < 1e-6) return -1;
    float t = (py - ro.y) / rd.y;
    return t > 0 ? t : -1;
}

V trace(V ro, V rd) {
    float ts = intersect_sphere(ro, rd, sph_center, sph_r);
    float tp = intersect_plane(ro, rd, plane_y);

    float t;
    int hit_sphere = 0, hit_plane = 0;

    if (ts > 0 && tp > 0) {
        if (ts < tp) { t = ts; hit_sphere = 1; }
        else { t = tp; hit_plane = 1; }
    } else if (ts > 0) { t = ts; hit_sphere = 1; }
    else if (tp > 0) { t = tp; hit_plane = 1; }
    else {
        // Sky
        V n = vnorm(rd);
        float a = 0.5 * (n.y + 1.0);
        V col = vadd(vmul(v(1,1,1), 1.0-a), vmul(v(0.5, 0.7, 1.0), a));
        return col;
    }

    V pos = vadd(ro, vmul(rd, t));
    V N, color;

    if (hit_sphere) {
        N = vnorm(vsub(pos, sph_center));
        color = v(0.2, 0.04, 0.04);
    } else {
        N = v(0, 1, 0);
        int cx = (int)floorf(pos.x);
        int cz = (int)floorf(pos.z);
        float checker = ((cx + cz) & 1) ? 0.7 : 0.4;
        color = v(checker, checker, checker);
    }

    // Lighting
    V light_dir = vnorm(vsub(light, pos));
    float diff = fmaxf(vdot(N, light_dir), 0.0);

    // Shadow
    V shadow_orig = vadd(pos, vmul(N, 0.001));
    float shadow_t = intersect_sphere(shadow_orig, light_dir, sph_center, sph_r);
    float shadow_p = intersect_plane(shadow_orig, light_dir, plane_y);
    int in_shadow = 0;
    if (shadow_t > 0.01) in_shadow = 1;
    if (shadow_p > 0.01 && shadow_p < vlen(vsub(light, pos))) in_shadow = 1;

    float ambient = 0.2;
    float lighting = in_shadow ? ambient : (ambient + 0.8 * diff);
    return vmul(color, lighting);
}

int main() {
    int W = 2400, H = 1800;
    FILE *f = fopen("reconstructed.ppm", "w");
    fprintf(f, "P3\n%d %d\n255\n", W, H);

    float aspect = (float)W / H;
    float fov = 2.0; // focal length related

    for (int y = 0; y < H; y++) {
        for (int x = 0; x < W; x++) {
            float u = (2.0 * (x + 0.5) / W - 1.0) * aspect;
            float v_y = 1.0 - 2.0 * (y + 0.5) / H;
            V rd = vnorm(v(u, v_y, fov));
            V col = trace(cam, rd);
            int r = (int)(fminf(col.x, 1.0) * 255.99);
            int g = (int)(fminf(col.y, 1.0) * 255.99);
            int b = (int)(fminf(col.z, 1.0) * 255.99);
            fprintf(f, "%d %d %d\n", r, g, b);
        }
    }
    fclose(f);
    return 0;
}
